export function getShapeKey(t) {
  const type = (t || '').toUpperCase().replace(/[-\s]/g, '')

  if (/BLIMP|ZEPPELIN|AIRSHIP/.test(type)) return 'blimp'
  if (/BALLOON|AEROSTAT/.test(type)) return 'balloon'
  if (/^PARA/.test(type)) return 'para'

  if (/MQ9|MQ1B?|MQ1C|RQ4|RQ7|RQ170|REAPER|PREDATOR|GLOBALHAWK|TRITON|HERON|HERMES|WATCHKEEPER/.test(type)) return 'uav'
  if (/V22|MV22|CV22|OSPREY/.test(type)) return 'v22_fast'
  if (/CH47|CH146|MH47|H47|CHINOOK/.test(type)) return 'chinook'
  if (/AH64|H64|APACHE/.test(type)) return 'apache'
  if (/MI24|MI25|MI35|HIND/.test(type)) return 'mil24'
  if (/CH53|S61|S64|S65|S92|MH53|HH53|EH10|EH101|MERLIN/.test(type)) return 's61'
  if (/UH60|HH60|SH60|MH60|H60|BLACKHAWK/.test(type)) return 'blackhawk'
  if (/AS365|AS65|EC155|EC55|DAUPHIN/.test(type)) return 'dauphin'
  if (/SA342|GAZELLE/.test(type)) return 'gazelle'
  if (/AS332|AS532|EC225|EC25|EC725|PUMA|COUGAR|SUPERPUMA/.test(type)) return 'puma'
  if (/GYRO|AUTOGYRO/.test(type)) return 'gyrocopter'
  if (/^UH|^AH|^MH|^HH|^SH|^H6|^H4|^H7|^H9|EC135|EC35|EC145|EC45|EC665|W3A?|MI8|MI17|MI28|KA50|KA52|LYNX|SEAHAWK|WILDCAT|R44|R66|A139|AW139|AW149|AW169|AW189|A149|A169|NH90|NH9|MD9[02]|EXPLORER/.test(type)) return 'helicopter'

  if (/B1B|LANCER/.test(type)) return 'b1b_lancer'
  if (/B52|STRATOFORTRESS/.test(type)) return 'b52'
  if (/TORNADO/.test(type)) return 'tornado'
  if (/^A10|WARTHOG/.test(type)) return 'a10'
  if (/^U2$|^TR1$/.test(type)) return 'u2'

  if (/F35|LIGHTNING/.test(type)) return 'f35'
  if (/F15|EAGLE/.test(type)) return 'md_f15'
  if (/F18|FA18|HORNET/.test(type)) return 'f18'
  if (/EF2000|TYPHOON/.test(type)) return 'typhoon'
  if (/^RAFALE/.test(type)) return 'rafale'
  if (/MIRAGEF1/.test(type)) return 'miragef1'
  if (/^MIRAGE/.test(type)) return 'mirage'
  if (/JAS39|GRIPEN|SB39/.test(type)) return 'sb39'
  if (/ALPHAJET|ALPHAJ/.test(type)) return 'alpha_jet'
  if (/^HAWK|BAEHAWK/.test(type)) return 'bae_hawk'
  if (/L159|ALCA/.test(type)) return 'l159'
  if (/MB326|M326|M346/.test(type)) return 'm326'
  if (/^T38|TALON/.test(type)) return 't38'
  if (/^F5[A-Z]?$|^F5E$/.test(type)) return 'f5_tiger'
  if (/^A4$|TA4|SKYHAWK/.test(type)) return 'md_a4'
  if (/^HUNTER/.test(type)) return 'hunter'
  if (/MIG21|MIG23|FISHBED|FLOGGER/.test(type)) return 'mirage'
  if (/^SU25|FROGFOOT/.test(type)) return 'a10'
  if (/F16|MIG29|MIG31|SU27|SU30|SU35|SU57|FLANKER|FULCRUM|VIPER/.test(type)) return 'hi_perf'

  if (/^C17[A-Z]?$|GLOBEMASTER/.test(type)) return 'c17'
  if (/^C5[A-Z]?$|GALAXY/.test(type)) return 'c5'
  if (/SUPERGUPPY/.test(type)) return 'super_guppy'
  if (/BELUGA/.test(type)) return 'beluga'
  if (/^E3|AWACS|SENTRY/.test(type)) return 'e3awacs'
  if (/E737|WEDGETAIL/.test(type)) return 'e737'
  if (/^P8|POSEIDON/.test(type)) return 'p8'
  if (/^P3|^EP3|ORION/.test(type)) return 'p3_orion'
  if (/^C2$|^E2$|HAWKEYE|GREYHOUND/.test(type)) return 'c2'
  if (/RC135|JSTARS|SENTINEL/.test(type)) return 'b707'
  if (/^KC135|^K35[RT]/.test(type)) return 'b707'
  if (/^KC46|^KC10|^MRTT|A330MRT/.test(type)) return 'heavy_2e'
  if (/C130|C13J|C30J|C160|AN12|HERCULES/.test(type)) return 'c130'
  if (/IL76|IL78|CANDID/.test(type)) return 'heavy_4e'
  if (/A400|A400M/.test(type)) return 'a400'

  // Business jets (swept-wing twin-engine)
  if (/^GL[5-9]T|^GLEX|^GLXS/.test(type)) return 'jet_swept'     // Bombardier Global 5000-7500
  if (/^CL[36][05]|^CL30/.test(type)) return 'jet_swept'          // Bombardier Challenger 300/600
  if (/GLF[3-9]/.test(type)) return 'jet_swept'                   // Gulfstream III-VI (old codes)
  if (/^G[2-9][05]0$|^G[2-9][0-9][0-9]$/.test(type)) return 'jet_swept'  // Gulfstream G280-G800
  if (/^F900|^FA7X|^FA50|^F2TH/.test(type)) return 'jet_swept'   // Dassault Falcon
  if (/^LJ[2-9][0-9]/.test(type)) return 'jet_swept'              // Learjet
  if (/^H25[A-Z]|^HAWKER/.test(type)) return 'jet_swept'          // Hawker/BAe 125
  if (/^E55P|^E50P|^GALX|^PC24/.test(type)) return 'jet_swept'   // Other biz jets

  if (/B747|B748|B744/.test(type)) return 'heavy_4e'
  if (/A380/.test(type)) return 'a380'
  if (/A340|IL96/.test(type)) return 'heavy_4e'
  if (/IL62/.test(type)) return 'il_62'
  if (/B76[234WZ]|B767|B77[23LW89]|B777|B78[79X]|B787|MD11|DC10/.test(type)) return 'heavy_2e'
  if (/A332|A333|A338|A339/.test(type)) return 'heavy_2e'
  if (/A350|A359|A35K/.test(type)) return 'a359'
  if (/B707/.test(type)) return 'b707'
  if (/AN124|AN225/.test(type)) return 'heavy_4e'
  if (/A319|A21N/.test(type)) return 'a319'
  if (/A321/.test(type)) return 'a321'
  if (/A320|A318|A20N/.test(type)) return 'a320'
  if (/B73[0-9]|B38M|B39M/.test(type)) return 'a319'
  if (/E39[0-9]|E29[0-9]|E17[0-9]|E19[0-9]|E13[0-9]|E14[0-9]|RJ[0-9]|B46[123]/.test(type)) return 'e390'
  if (/C295|CN235|C235|C212|AN26|AN32|DHC6|DHC5|CASA|C27J|C27/.test(type)) return 'twin_large'
  if (/M28|SKYTRUCK|BRYZA/.test(type)) return 'single_turbo'
  if (/ATR|PC6|CARAVAN|C208/.test(type)) return 'single_turbo'
  if (/KINGAIR|PC12|PC21|PC9|PC7|DHC8|DASH8|BE20|BE9|C12/.test(type)) return 'twin_small'
  if (/CESSNA|C172|C182|C152|G115|G120|G140|SF260|SF50|PZL130|TB[0-9]|TB20|TB21/.test(type)) return 'cessna'
  if (/CIRRUS|SR22|SR20/.test(type)) return 'cirrus_sr22'
  if (/^PA[23]/.test(type)) return 'pa24'
  if (/GLIDER|SAILPLANE|^ASK|^ASW/.test(type)) return 'glider'

  return 'jet_swept'
}

